external_knowledge:
- "braved the stormy skies" refers to flying under rainy weather conditions;
- "covering more than a marathon distance" is a metaphor for a route distance greater than 50 km, considering a marathon distance is about 42.2 km;
- "more than half of their fuel tank" refers to battery levels above 50%.

sql:
SELECT drone_id, drone_type
FROM drones
WHERE speed > (SELECT AVG(speed) FROM drones);

external_knowledge:
- "ventured out on the seas of the sky" metaphorically refers to drones conducting flights;
- "voyages" is a metaphorical term for individual flights;
- "most adventurous" refers to drones with the highest number of flights.

- 'halfway charged' refers to the battery level being greater than 50%;
- 'completed their flights' indicates the flight has a non-null finish date;
- 'average speeds' are calculated per drone, considering only the flights that have been completed.

sql:
SELECT SUM(route_distance) 
FROM flights 
WHERE drone_id = 1;

SELECT weather_id, temperature, humidity, wind_speed, weather_condition
FROM weather_data
WHERE flight_id = (SELECT flight_id FROM flights WHERE date_finished = (SELECT MAX(date_finished) FROM flights));
